```json
{
  "global": "Navigate to the job search portal, apply filters for internship roles targeting university graduates in Germany posted within the last 7 days, locate the matching listing, and submit an application.",
  "subtasks": [
    {
      "subtask": "Open the job search interface",
      "atomics": [
        "Click or navigate to the Jobs / Career portal module",
        "Confirm the job search form or listing page is loaded"
      ]
    },
    {
      "subtask": "Filter job listings to internships in Germany posted in the last 7 days",
      "atomics": [
        "Set the Job Type or Category filter to 'Internship'",
        "Set the Location filter to 'Germany'",
        "Set the Education Level or Applicant Type filter to 'University Graduate'",
        "Set the Date Posted filter to 'Last 7 days' (or equivalent recency option)",
        "Execute the search to apply all filters"
      ]
    },
    {
      "subtask": "Identify and open the target internship posting",
      "atomics": [
        "Scan the filtered results for an internship role matching the university-graduate / Germany criteria",
        "Click on the job title to open the full job detail page",
        "Verify the posting date falls within the last 7 days"
      ]
    },
    {
      "subtask": "Complete and submit the job application",
      "atomics": [
        "Click the 'Apply' or 'Apply Now' button on the job detail page",
        "Fill in required application fields (name, contact, resume/CV upload, cover letter if required)",
        "Review all entered information for correctness",
        "Click the final 'Submit Application' button"
      ]
    }
  ],
  "global_atomics": [
    "Confirm the on-screen success or confirmation message indicating the application was received"
  ],
  "gold_actions": {
    "global": "Use the portal's job search page to query type=Internship, location=Germany, education=University Graduate, date_posted=last_7_days, then open the returned listing and submit the application form.",
    "subtasks": [
      {
        "subtask": "Open the job search interface",
        "atomics": [
          "Click the 'Jobs' or 'Careers' navigation link in the portal header or sidebar",
          "Assert that the job search/listing page renders with a visible search or filter panel"
        ]
      },
      {
        "subtask": "Filter job listings to internships in Germany posted in the last 7 days",
        "atomics": [
          "Select 'Internship' from the Job Type dropdown or checkbox group",
          "Type or select 'Germany' in the Location / Country filter field",
          "Select 'University Graduate' (or equivalent) from the Education / Candidate Level filter",
          "Select 'Last 7 days' from the Date Posted / Posted Within dropdown",
          "Click the 'Search' or 'Apply Filters' button and wait for results to refresh"
        ]
      },
      {
        "subtask": "Identify and open the target internship posting",
        "atomics": [
          "Read the job title, location, and posted-date on each result card to find a match",
          "Click the matching internship job title link to open its detail page",
          "Read the 'Posted on' date field on the detail page and confirm it is ≤ 7 days ago"
        ]
      },
      {
        "subtask": "Complete and submit the job application",
        "atomics": [
          "Click the 'Apply Now' button on the job detail page to open the application form",
          "Fill in personal details, upload or attach CV/resume, and add a cover letter if the form requires it",
          "Scroll through the form and verify all mandatory fields (marked with *) are populated",
          "Click 'Submit' or 'Send Application' to finalize the submission"
        ]
      }
    ],
    "global_atomics": [
      "Read the confirmation banner or modal text (e.g., 'Your application has been submitted') to verify successful submission"
    ]
  }
}
```
